// Cluster KEY precedence: the row's own cluster_label → its intent → a leading-token bucket.
// The keyword-research brick already writes cluster_label; intent is the next-best theme; the
// leading token is the deterministic last resort so EVERY kw finding lands in exactly one bucket.
function clusterKeyFor(f) {
  const ev = (f && f.evidence) || {};
  const cl = ev.cluster_label != null ? String(ev.cluster_label).trim() : '';
  if (cl) return { key: 'cl:' + cl.toLowerCase(), label: cl };
  const intent = ev.intent != null ? String(ev.intent).trim() : '';
